INSERT INTO templates (title, description, category, tags, cover_image, is_featured, fields, settings) VALUES ('MBTI 十六型人格测试', '经典 MBTI 性格测试，测测你是哪种人格类型？适合小红书分享', 'personality', ARRAY['MBTI','性格测试','小红书'], NULL, true, '[{"id":"q1","type":"radio","label":"周末你更喜欢？","required":true,"options":["约朋友出去玩","在家独处充电"]},{"id":"q2","type":"radio","label":"做决定时，你更倾向于？","required":true,"options":["跟着感觉走","理性分析利弊"]},{"id":"q3","type":"radio","label":"和朋友聊天时，你更喜欢？","required":true,"options":["天马行空聊未来","分享具体的经历"]},{"id":"q4","type":"radio","label":"面对deadline，你通常？","required":true,"options":["提前规划好一切","临近才爆发"]},{"id":"q5","type":"radio","label":"聚会时你是？","required":true,"options":["全场焦点，热场王","安静观察，小范围聊"]},{"id":"q6","type":"radio","label":"你更相信？","required":true,"options":["直觉和第六感","数据和事实"]},{"id":"q7","type":"radio","label":"别人向你诉苦时，你会？","required":true,"options":["先安慰对方情绪","先帮忙分析问题"]},{"id":"q8","type":"radio","label":"旅行时你更喜欢？","required":true,"options":["详细攻略按计划走","随心所欲走到哪算哪"]},{"id":"q9","type":"rating","label":"你觉得自己的社交能量有多强？","required":true,"maxRating":5},{"id":"q10","type":"radio","label":"学习新事物时，你偏好？","required":true,"options":["先看全局框架","从细节入手"]}]'::jsonb, '{"displayMode":"step","theme":{"primaryColor":"#8b5cf6","backgroundColor":"#faf5ff","fontFamily":"rounded","thankYouMessage":"测试完成！你的MBTI类型已生成"},"scoringMode":true,"scoreRanges":[{"min":0,"max":4,"label":"INFP 调停者","description":"你是一个理想主义者，内心世界丰富，追求意义和真实。"},{"min":5,"max":6,"label":"ENFJ 主人公","description":"你天生具有领导力，善于激励他人，是团队中的灵魂人物。"},{"min":7,"max":8,"label":"INTJ 建筑师","description":"你是一个战略思想家，独立而有远见，喜欢计划和优化一切。"},{"min":9,"max":10,"label":"ESTP 企业家","description":"你精力充沛，喜欢冒险和新鲜感，是行动派的代表。"}]}'::jsonb);
INSERT INTO templates (title, description, category, tags, cover_image, is_featured, fields, settings) VALUES ('闺蜜默契度大考验', '测测你和闺蜜的默契指数！转发给她一起做吧', 'social', ARRAY['闺蜜','默契','朋友圈'], NULL, true, '[{"id":"q1","type":"radio","label":"如果闺蜜突然哭了，你第一反应是？","required":true,"options":["递纸巾默默陪着","问怎么了谁欺负你","拉她出去吃好吃的","直接帮她骂人"]},{"id":"q2","type":"radio","label":"闺蜜约你出门，你觉得她最可能穿？","required":true,"options":["休闲运动风","小裙子淑女风","酷酷的街头风","什么都有可能"]},{"id":"q3","type":"radio","label":"你们最常一起做的事？","required":true,"options":["逛街购物","在家追剧/打游戏","吃遍美食","聊天八卦到天亮"]},{"id":"q4","type":"radio","label":"闺蜜最讨厌什么类型的人？","required":true,"options":["虚伪做作的","太粘人的","不守信用的","我也不太确定"]},{"id":"q5","type":"radio","label":"如果你们吵架了，通常谁先和好？","required":true,"options":["我先","她先","谁也不服谁但第二天就好了","我们从不吵架"]},{"id":"q6","type":"rating","label":"给你们的默契度打个分","required":true,"maxRating":5,"ratingIcon":"heart"},{"id":"q7","type":"text","label":"用一句话形容你的闺蜜","required":false,"placeholder":"写点什么..."}]'::jsonb, '{"displayMode":"step","theme":{"primaryColor":"#ec4899","backgroundColor":"#fdf2f8","fontFamily":"rounded","thankYouMessage":"默契度测试完成！快分享给闺蜜看看她怎么答"}}'::jsonb);
INSERT INTO templates (title, description, category, tags, cover_image, is_featured, fields, settings) VALUES ('你是什么味道的奶茶？', '根据你的性格测出专属奶茶口味，小红书爆款测试', 'fun', ARRAY['奶茶','趣味','小红书爆款'], NULL, true, '[{"id":"q1","type":"radio","label":"早上起床你的状态是？","required":true,"options":["元气满满立刻起","赖床十分钟再说","闹钟响N次才醒","不存在早起这回事"]},{"id":"q2","type":"radio","label":"你的朋友圈风格是？","required":true,"options":["精修美图+文案","随手拍日常","只发重要时刻","潜水党/很少发"]},{"id":"q3","type":"radio","label":"你的穿搭风格偏向？","required":true,"options":["简约黑白灰","甜美可爱风","随性舒适","百变不固定"]},{"id":"q4","type":"radio","label":"你更享受？","required":true,"options":["和朋友热闹聚会","两三好友深度聊天","一个人的安静时光","看情况都行"]},{"id":"q5","type":"radio","label":"遇到困难你的态度是？","required":true,"options":["冲！没在怕的","先想想再行动","找朋友商量","等等看会不会自己好"]}]'::jsonb, '{"displayMode":"step","theme":{"primaryColor":"#f59e0b","backgroundColor":"#fffbeb","fontFamily":"rounded","thankYouMessage":"你的专属奶茶口味已揭晓"},"scoringMode":true,"scoreRanges":[{"min":0,"max":2,"label":"茉莉奶绿","description":"清新淡雅的你，像一杯茉莉奶绿，让人感到舒适放松。"},{"min":3,"max":4,"label":"珍珠奶茶","description":"经典百搭的你，像珍珠奶茶一样人见人爱，好相处！"},{"min":5,"max":6,"label":"芋泥波波","description":"软糯可爱的你，外表温柔内心丰富，给人甜甜的感觉。"}]}'::jsonb);
INSERT INTO templates (title, description, category, tags, cover_image, is_featured, fields, settings) VALUES ('恋爱人格小测试', '测测你在恋爱中是什么类型？了解自己的爱情模式', 'social', ARRAY['恋爱','爱情','情感'], NULL, false, '[{"id":"q1","type":"radio","label":"你理想的约会方式是？","required":true,"options":["一起看电影/展览","在家做饭看剧","出去探险/旅行","逛街吃美食"]},{"id":"q2","type":"radio","label":"吵架后你通常会？","required":true,"options":["主动认错和好","冷静一会儿再沟通","等对方来找自己","直接说清楚想法"]},{"id":"q3","type":"radio","label":"你最看重伴侣的？","required":true,"options":["颜值/气质","幽默感","上进心","对我好/体贴"]},{"id":"q4","type":"radio","label":"你的恋爱频率是？","required":true,"options":["经常恋爱","偶尔恋爱","很少恋爱","母胎solo"]},{"id":"q5","type":"radio","label":"你觉得恋爱中最重要的是？","required":true,"options":["安全感","新鲜感","自由空间","共同成长"]},{"id":"q6","type":"rating","label":"你觉得自己恋商有多高？","required":true,"maxRating":5,"ratingIcon":"heart"}]'::jsonb, '{"displayMode":"step","theme":{"primaryColor":"#e11d48","backgroundColor":"#fff1f2","fontFamily":"rounded","thankYouMessage":"你的恋爱人格已揭晓"},"scoringMode":true,"scoreRanges":[{"min":0,"max":2,"label":"自由型恋人","description":"你在恋爱中注重独立空间，不会过度依赖对方。"},{"min":3,"max":4,"label":"浪漫型恋人","description":"你追求仪式感和浪漫，善于营造甜蜜氛围。"},{"min":5,"max":6,"label":"热烈型恋人","description":"你全身心投入恋爱，爱得热烈真诚。"}]}'::jsonb);
INSERT INTO templates (title, description, category, tags, cover_image, is_featured, fields, settings) VALUES ('活动满意度调查', '通用活动反馈模板，适用于各类线下/线上活动', 'utility', ARRAY['满意度','活动','反馈'], NULL, false, '[{"id":"q1","type":"text","label":"您的姓名（选填）","required":false,"placeholder":"请输入"},{"id":"q2","type":"radio","label":"您是通过什么渠道了解本次活动的？","required":true,"options":["朋友推荐","社交媒体","公众号/邮件","其他"]},{"id":"q3","type":"rating","label":"您对本次活动整体满意度如何？","required":true,"maxRating":5,"ratingIcon":"star"},{"id":"q4","type":"rating","label":"活动内容质量","required":true,"maxRating":5,"ratingIcon":"star"},{"id":"q5","type":"rating","label":"活动组织安排","required":true,"maxRating":5,"ratingIcon":"star"},{"id":"q6","type":"checkbox","label":"您最喜欢哪些环节？（多选）","required":false,"options":["主题分享","互动环节","抽奖/礼品","社交交流","茶歇/餐饮"]},{"id":"q7","type":"text","label":"您有什么建议或期望？","required":false,"multiline":true,"placeholder":"请畅所欲言..."},{"id":"q8","type":"radio","label":"您是否愿意参加下次活动？","required":true,"options":["非常愿意","看情况","不太想"]}]'::jsonb, '{"displayMode":"page","theme":{"primaryColor":"#06b6d4","backgroundColor":"#f0fdfa","fontFamily":"default","thankYouMessage":"感谢您的反馈！我们会努力做得更好"}}'::jsonb);
INSERT INTO templates (title, description, category, tags, cover_image, is_featured, fields, settings) VALUES ('你的动物人格是？', 'AI角色对话版：和可爱的占卜师聊天，测出你的动物灵魂', 'personality', ARRAY['动物','AI对话','角色扮演'], NULL, true, '[{"id":"q1","type":"radio","label":"你的性格特点","required":true,"options":["温柔安静","活泼外向","独立自主","忠诚可靠"]},{"id":"q2","type":"radio","label":"你喜欢的生活节奏","required":true,"options":["慢悠悠","快节奏","有规律","随心情"]},{"id":"q3","type":"radio","label":"你的社交风格","required":true,"options":["小圈子深交","广交朋友","独来独往","看心情"]}]'::jsonb, '{"displayMode":"chat","chatRole":"星灵占卜师","chatScene":"神秘的星空占卜屋，水晶球散发着柔和的光芒","chatOpening":"欢迎来到星灵占卜屋，我是占卜师小星，让我通过几个问题来揭示你内心深处的动物灵魂吧！准备好了吗？","chatPersonality":"温柔、神秘、有趣","chatTone":"轻松活泼，偶尔神秘","chatHabit":"喜欢用星星emoji","chatAvatarStyle":"lorelei","chatFeatures":{"mood":true,"scene":true,"suggest":true,"bond":true},"theme":{"primaryColor":"#7c3aed","backgroundColor":"#1a1a2e","fontFamily":"rounded","thankYouMessage":"占卜完成！你的动物灵魂已揭晓"}}'::jsonb);
